LIBS["digital"] = {"_comment":["Bibliothèque de FONCTIONS DIGITALES (manipulations non-temporelles) — jumeau DIGITAL des objets","CV (lib/mod.json) : même structure {type, objects}, mais le comportement = VRAI CODE TS réalisé par","KAIROS (vs courbe déclarative réalisée par le runtime audio). Spec : docs/design/DIGITAL_FUNCTIONS.md.","Jeu FOURNI (lecture seule) ; perso/communautaire = surcharge hôte via registerLib (3 provenances).","Chaque fonction : { params (signature typée, jumelle des params CV) }. Le `body` (code TS) n'est PAS","ici : authoring F1 = un VRAI .ts TYPÉ dans lib/digital/<fn>.ts (contre le SDK @kairos/core), dont","libs-bundle.js capte le SOURCE en `body` dans libs-data.js. Type-check : `npm run typecheck:digital`.","SIGNATURE SCELLÉE (Romain) : (ctx: DigitalFnContext) => void — la fonction MODIFIE ctx.target (une","COPIE préparée par Kairos, JAMAIS l'arbre réel ; Kairos seul applique le résultat à la sortie","canonique). body capté = TS SOURCE, transpilé au load par Kairos (sucrase)."],"name":"digital","type":"digital","objects":{"transpose":{"description":"Transposition — décalage de N pas sur la grille du tempérament (C4 +2 → D4 en 12-TET).","params":{"steps":{"type":"int","default":0,"description":"Nombre de pas de grille (peut être négatif)."}},"body":"// Corps de la fonction digitale `transpose` — AUTHORING F1 (vrai .ts TYPÉ contre le SDK Kairos).\n// Source de vérité : ce fichier ; libs-bundle.js en capte le SOURCE dans lib/digital.json → libs-data.js.\n// Kairos transpile (sucrase, qui STRIPE l'`import type`) puis exécute au load. Spec : docs/design/DIGITAL_FUNCTIONS.md.\nimport type { DigitalFn } from '@kairos/core';\n\n/** transpose — décalage de N pas sur la grille du tempérament (do4 +2 → ré4 en 12-TET). */\nconst transpose: DigitalFn = (ctx) => {\n  // Mutation de la COPIE (ctx.target) ; Kairos dérive le Hz APRÈS (L16). `step` = axe de grille.\n  if (ctx.target.pitch) ctx.target.pitch.step += Number(ctx.params.steps ?? 0);\n};\n\nexport default transpose;\n"}}};

